body.script:
jQuery(function($) {

    //Comportamenti non previsti in Yith Ajax Filter
    $('body').on('click', 'a[data-filters*="product_cat"]', () => {
        if ( $('a[data-filters*="product_cat"]').length == 1 ) {
            window.location.href = "https://www.pedrollo.com/prodotti/";
        }
    });

    $('body').on('click', 'a[data-filters*="product_tag"]', () => {
        if ( $('a[data-filters*="product_tag"]').length == 1 ) {
            window.location.href = "https://www.pedrollo.com/prodotti/";
        }
    });

    //Gestione dei filtri WooCommerce Yith Ajax Filter, per rendere visibili gli elementi quando serve
    //Ambito e sottoambito
    let filterIds = {
        ambitoUtilizzo: [
            'filter_2960_1',
            'filter_2961_1',
            'filter_3419_1',
            'filter_5543_1',
            'filter_5744_1'
        ],
        sottoAmbitoUtilizzo1: [
            'filter_2960_2',
            'filter_2961_2',
            'filter_3419_2',
            'filter_5543_2',
            'filter_5744_2'
        ],
        sottoAmbitoUtilizzo2: [
            'filter_2960_3',
            'filter_2961_3',
            'filter_3419_3',
            'filter_5543_3',
            'filter_5744_3'
        ],
        sottoAmbitoUtilizzo3: [
            'filter_2960_4',
            'filter_2961_8',
            'filter_3419_4',
            'filter_5543_4',
            'filter_5744_4'
        ],
        sottoAmbitoUtilizzo4: [
            'filter_2960_5',
            'filter_2961_5',
            'filter_3419_5',
            'filter_5543_5',
            'filter_5744_5'
        ],
        sottoAmbitoUtilizzo5: [
            'filter_2960_6',
            'filter_2961_4',
            'filter_3419_6',
            'filter_5543_6',
            'filter_5744_6'
        ],
        tipologia: [
            'filter_2960_7',
            'filter_2961_7',
            'filter_3419_7',
            'filter_5543_7',
            'filter_5744_7'
        ],
        materialeGirante: [
            'filter_2960_8',
            'filter_2961_9',
            'filter_3419_8',
            'filter_5543_8',
            'filter_5744_8'
        ],
        dimensionePozzo: [
            'filter_2960_9',
            'filter_2961_10',
            'filter_3419_9',
            'filter_5543_9',
            'filter_5744_9'
        ],
        portataOrig: [
            'filter_2960_10',
            'filter_2961_11',
            'filter_3419_10',
            'filter_5543_10',
            'filter_5744_10'
        ],
        materialeCorpo: [
            'filter_2960_11',
            'filter_2961_12',
            'filter_3419_15',
            'filter_5543_14',
            'filter_5744_11'
        ],
        passaggioLibero: [
            'filter_2960_12',
            'filter_2961_13',
            'filter_3419_13',
            'filter_5543_16',
            'filter_5744_12'
        ],
        tipologiaGirante: [
            'filter_2960_13',
            'filter_2961_14',
            'filter_3419_14',
            'filter_5543_17',
            'filter_5744_13'
        ],
        portata: [
            'filter_flowrate',
        ]
    }

    let ambitoUtilizzoSelector = filterIds.ambitoUtilizzo.map(e => '.yith-wcan-filters #' + e + '.yith-wcan-filter').join(', ');

    let sottoAmbitoUtilizzoSelector = [
        filterIds.sottoAmbitoUtilizzo1.map(e => '.yith-wcan-filters #' + e + '.yith-wcan-filter').join(', '),
        filterIds.sottoAmbitoUtilizzo2.map(e => '.yith-wcan-filters #' + e + '.yith-wcan-filter').join(', '),
        filterIds.sottoAmbitoUtilizzo3.map(e => '.yith-wcan-filters #' + e + '.yith-wcan-filter').join(', '),
        filterIds.sottoAmbitoUtilizzo4.map(e => '.yith-wcan-filters #' + e + '.yith-wcan-filter').join(', '),
        filterIds.sottoAmbitoUtilizzo5.map(e => '.yith-wcan-filters #' + e + '.yith-wcan-filter').join(', ')
    ];

    let tipologiaSelector = filterIds.tipologia.map(e => '.yith-wcan-filters #' + e + '.yith-wcan-filter').join(', ');
    let materialeGiranteSelector = filterIds.materialeGirante.map(e => '.yith-wcan-filters #' + e + '.yith-wcan-filter').join(', ');
    let dimensionePozzoSelector = filterIds.dimensionePozzo.map(e => '.yith-wcan-filters #' + e + '.yith-wcan-filter').join(', ');
    let portataSelector = filterIds.portata.map(e => '.yith-wcan-filters #' + e + '.yith-wcan-filter').join(', ');
    let materialeCorpoSelector = filterIds.materialeCorpo.map(e => '.yith-wcan-filters #' + e + '.yith-wcan-filter').join(', ');
    let passaggioLiberoSelector = filterIds.passaggioLibero.map(e => '.yith-wcan-filters #' + e + '.yith-wcan-filter').join(', ');
    let tipologiaGiranteSelector = filterIds.tipologiaGirante.map(e => '.yith-wcan-filters #' + e + '.yith-wcan-filter').join(', ');
    let portataOrigSelector = filterIds.portataOrig.map(e => '.yith-wcan-filters #' + e + '.yith-wcan-filter').join(', ');

    let sommerseIds = {
        motoriSommersi: [
            'filter_2960_7_154',
            'filter_2961_7_593',
            'filter_3419_7_866',
            'filter_5543_7_937',
            'filter_5744_7_1115'
        ],
        pompeSommerse: [
            'filter_2960_7_152',
            'filter_2961_7_591',
            'filter_3419_7_868',
            'filter_5543_7_939',
            'filter_5744_7_1117'
        ],
        centrifughe: [
            'filter_2960_7_139',
            'filter_2961_7_356',
            'filter_3419_7_398',
            'filter_5543_7_941',
            'filter_5744_7_1119'
        ],
        acqueReflue: [
            'filter_2960_7_40',
            'filter_2961_7_346',
            'filter_3419_7_386',
            'filter_5543_7_932',
            'filter_5744_7_1110'
        ]
    };

    //let sommerseSelector = Object.values( sommerseIds ).flat().map(e => tipologiaSelector + ' input#' + e).join(', ');
    let motoriSommersiSelector = sommerseIds.motoriSommersi.map(e => '.yith-wcan-filters input#' + e).join(', ');
    let pompeSommerseSelector  = sommerseIds.pompeSommerse.map (e => '.yith-wcan-filters input#' + e).join(', ');
    let centrifugheSelector    = sommerseIds.centrifughe.map   (e => '.yith-wcan-filters input#' + e).join(', ');
    let acqueReflueSelector    = sommerseIds.acqueReflue.map   (e => '.yith-wcan-filters input#' + e).join(', ');


    //Gestione delle icone
    let tipologieIds = {
        superficie: [
            'filter_2960_7_43',
            'filter_2961_7_330',
            'filter_3419_7_394',
            'filter_5543_7_752',
            'filter_5744_7_755'
        ],
        sommerse: [
            'filter_2960_7_44',
            'filter_2961_7_352',
            'filter_3419_7_392',
            'filter_5543_7_934',
            'filter_5744_7_1112'
        ],
        sommergibili: [
            'filter_2960_7_89',
            'filter_2961_7_344',
            'filter_3419_7_384',
            'filter_5543_7_929',
            'filter_5744_7_1107'
        ],
        gruppiPressione: [
            'filter_2960_7_45',
            'filter_2961_7_278',
            'filter_3419_7_372',
            'filter_5543_7_960',
            'filter_5744_7_1138'
        ],
        quadriSistemi: [
            'filter_2960_7_46',
            'filter_2961_7_338',
            'filter_3419_7_378',
            'filter_5543_7_955',
            'filter_5744_7_1133'
        ],
        accessori: [
            'filter_2960_7_729',
            'filter_2961_7_1460',
            'filter_3419_7_2464',
            'filter_5543_7_2328',
            'filter_5744_7_2513'
        ],
    };


    //Aggiusta la visibilità di svariati elementi
    function adjustVisibility() {

        //Gestione dell'offcanvas
        let offCSPoint = $('#offcanvasStartingPoint');
        if (offCSPoint.children().length > 0 ) {
            let test = offCSPoint.children().first().detach();
            $('#offcanvasFilter').find('.offcanvas-body').empty().append(test);
        }

        //Funzione di visibilità
        let visibilityFn = ( selector, viewCondition ) => viewCondition ? $(selector).show() : $(selector).hide();

        //Visibilità del sottoAmbito
        let ambitiUtilizzo = $(ambitoUtilizzoSelector).find('li');
        let ambitoSelected = $(ambitoUtilizzoSelector).find('li.active');
        let selectedAmbitoIndex = ambitiUtilizzo.toArray().map(e => e).indexOf( ambitoSelected[0] );

        for( let i in sottoAmbitoUtilizzoSelector ) {
            visibilityFn(sottoAmbitoUtilizzoSelector[i], i == selectedAmbitoIndex);

            if (i == selectedAmbitoIndex) {
                //$(sottoAmbitoUtilizzoSelector[i]).css('background-color', 'red');
            }

            if ( i != selectedAmbitoIndex ) {
                //$(sottoAmbitoUtilizzoSelector[i]).css('background-color', 'blue');
                $(sottoAmbitoUtilizzoSelector[i]).find('input[type="checkbox"]').each( (i,e) => {
                    if ( $(e).prop('checked') ) {
                        setTimeout( () => $(e).trigger('click'), 300 );
                    }
                });
            }

        }

        //Sottotipologie
        $(tipologiaSelector).find('li input[type="checkbox"]:checked').each( (i,e) => {
            // gestisce i filtri diretti su categoria (entrando su filtro categorai da menu), se il nodo superiore non è flaggato lo flagga 
            let $parentCheckbox = $(e).closest('li').parent().closest('li').find('input[type="checkbox"]').first();

            if ( $parentCheckbox.is(':not(:checked)') ) {
                $parentCheckbox.trigger('click');
            }
        });
        $(tipologiaSelector).find('li').each( (i,e) => $(e).find('input[type="checkbox"]').first().is(':checked') ? $(e).find('ul > li').show() : $(e).find('ul > li').hide() ); // visibilità dei coerente con la check principale
        //$(tipologiaSelector).find('li').each( (i,e) => $(e).find('input[type="checkbox"]').first().is(':checked') ? $(e).find('ul > li').css('background-color', 'white') : $(e).find('ul > li').css('background-color', 'yellow') ); // test con giallo evidenziato


        //Filtri specifici per tipologia
        let pompeSommerse = $(pompeSommerseSelector).toArray();
        let motoriSommersi = $(motoriSommersiSelector).toArray();
        let centrifughe = $(centrifugheSelector).toArray();
        let acqueReflue = $(acqueReflueSelector).toArray();

        let motoriSommersiSelected = motoriSommersi.some( e => $(e).is(':checked'));
        let pompeSommerseSelected = pompeSommerse.some( e => $(e).is(':checked'));
        let centrifugheSelected = centrifughe.some( e => $(e).is(':checked'));
        let acqueReflueSelected = acqueReflue.some( e => $(e).is(':checked'));

        visibilityFn(materialeGiranteSelector, pompeSommerseSelected);
        visibilityFn(dimensionePozzoSelector, pompeSommerseSelected || motoriSommersiSelected);
        visibilityFn(portataSelector, centrifugheSelected);
        visibilityFn(materialeCorpoSelector, acqueReflueSelected);
        visibilityFn(passaggioLiberoSelector, acqueReflueSelected);
        visibilityFn(tipologiaGiranteSelector, acqueReflueSelected);

        $(portataOrigSelector).hide();

        //Icone
        for( let key in tipologieIds ) {
            let curr = tipologieIds[ key ];

            for( let chkSelector of curr ) {
                $( '.yith-wcan-filters #' + chkSelector ).parent().parent().addClass('tipicon').addClass('tipicon-' + key);
            }
        }

        //Mette visibile dopo gli aggiustamenti di caricamento
        $('.yith-wcan-filters').css('display', 'block');

    }
    adjustVisibility();




    //FILTRO CUSTOM RANGE PER POTENZA
    let flowRateValues = [160,270,450,700,900,2400];

    let afterFilter = function() {

        let from = parseInt( $(".mea-flowrate").data('mea-from') );
        let to = parseInt( $(".mea-flowrate").data('mea-to' ) );

        if ( !$.fn.ionRangeSlider ) {
            console.warn('ionRangeSlider non disponibile: controllo enqueue/ordine script.');
            return;
        }

        $(".mea-flowrate").ionRangeSlider({
            type: "double",
            skin: "round",
            postfix: " ",
            values: flowRateValues,
            from: flowRateValues.indexOf(from),
            to:   flowRateValues.indexOf(to),
        }).show();
    }
    afterFilter();

    //Eventi
    let categoriesToPurge = [];
    $('body').on('click', '.yith-wcan-filters input[type="checkbox"]', (e) => {
        //Gestisce la rimozione di una checkbox delle tipologie di livello superiore verso le inferiori (ref. g59gk23)
        let $current = $(e.target);

        if ( !$current.is(':checked') ) {
            categoriesToPurge = $current.closest('li').find('ul li input[type="checkbox"]').map((i, e) => $(e).attr('value') ).get();
        }
    });

    $(document).on('yith-wcan-ajax-filtered', () => {
        console.log('after-filter');
        afterFilter();
        adjustVisibility();
    });


    $(document).on('yith_wcan_filters_parameters', ( e, params ) => {
        //Trasforma i parametri della request

        if (Object.keys(params).length !== 0 ) {

            //Gestione delle categorie, va in affiancamento a ref. g59gk23
            if ( categoriesToPurge && params.product_cat ) {
                for( let c of categoriesToPurge ) {
                    params.product_cat = params.product_cat.replace(c, '');
                }
                params.product_cat = params.product_cat.replace(/\++/, '+');
                params.product_cat = params.product_cat.replace(/^\+|\+$/, '');

                if ( /^\+?$/.test(params.product_cat) ) {
                    delete params.product_cat;
                }

                categoriesToPurge = [];
            }

            //params.filter_portata-massima
            let slider = $(".mea-flowrate").data('ionRangeSlider');
            if ( !slider || !slider.result ) return params;
            let range = flowRateValues.slice( slider.result.from, slider.result.to + 1);

            if ( range.length !== flowRateValues.length ) {
                params['filter_portata-massima'] = range.join(",");
                params['query_type_portata-massima'] = "or";
            }
            else {
                delete params['filter_portata-massima'];
                delete params['query_type_portata-massima'];
            }
        }

        console.log(params);
        return params;
    });

});
